const emails = [];

for (const item of $input.all()) {
  if (item.json?.accepted?.[0]) {
    emails.push(item.json.accepted[0]);
  }
}

return [
  {
    json: {
      email_list: emails.join('; ')
    }
  }
];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
if ($input.first().json.output.flower_species == null) {
  $input.first().json.output.flower_species = "coleus";
}

return $input.all();
